import{_ as e,c as a,o as t,a4 as r}from"./chunks/framework.CSPW6Mz1.js";const y=JSON.parse('{"title":"Salary","description":null,"frontmatter":{"title":"Salary","description":null,"date":"2023-02-19T00:00:00.000Z","lastmod":"2023-02-19T00:00:00.000Z"},"headers":[],"relativePath":"Non-Sorted/Finance/Salary.md","filePath":"Non-Sorted/Finance/Salary.md","lastUpdated":1690829560000}'),s={name:"Non-Sorted/Finance/Salary.md"},o=r('<h1 id="salary" tabindex="-1">Salary <a class="header-anchor" href="#salary" aria-label="Permalink to &quot;Salary&quot;">​</a></h1><h2 id="salary-structure" tabindex="-1">Salary Structure <a class="header-anchor" href="#salary-structure" aria-label="Permalink to &quot;Salary Structure&quot;">​</a></h2><p>A salary structure is the system used by organizations to determine how much employees are paid based on various factors such as their job title, experience, skills, and performance. It is a framework that outlines the compensation and benefits package offered to employees for their work</p><p>A typical salary structure includes several components such as:</p><ul><li><p>Base salary: This is the fixed amount of money an employee is paid on an annual or hourly basis for their job</p></li><li><p>Bonuses: These are one-time payments made to employees for achieving specific goals or targets</p></li><li><p>Benefits: These are non-monetary compensation provided to employees such as health insurance, retirement plans, paid time off, etc.</p></li><li><p>Incentives: These are payments or rewards that encourage employees to improve their performance or achieve specific goals</p></li><li><p>Allowances: These are additional payments made to employees for specific expenses such as travel, housing, or meals</p></li><li><p>Stock options: These are a type of incentive compensation that gives employees the right to purchase company stock at a discounted price</p></li></ul><p>Salary structures vary across organizations and industries, but they are essential for ensuring that employees are fairly compensated for their work and for attracting and retaining top talent. A well-designed salary structure can also help organizations to manage costs and stay competitive in the job market.</p>',6),i=[o];function n(l,c,p,d,h,u){return t(),a("div",null,i)}const f=e(s,[["render",n]]);export{y as __pageData,f as default};
